class PaymentProcessor {
    public PaymentResponse process(PaymentRequest request) {
        if (request == null) {
            return PaymentResponse.failure("INVALID_REQUEST", "Payment request is null");
        }
        if (request.getAmount() <= 0) {
            return PaymentResponse.failure("INVALID_AMOUNT", "Amount must be greater than zero");
        }
        if (request.getCurrency() == null || request.getCurrency().trim().isEmpty()) {
            return PaymentResponse.failure("INVALID_CURRENCY", "Currency is required");
        }
        if (request.getPaymentMethod() == null || request.getPaymentMethod().trim().isEmpty()) {
            return PaymentResponse.failure("INVALID_METHOD", "Payment method is required");
        }

        String lowerMethod = request.getPaymentMethod().trim().toLowerCase();
        String status;
        String transactionId = UUID.randomUUID().toString();

        if ("card".equals(lowerMethod) || "credit_card".equals(lowerMethod)) {
            status = "APPROVED";
        } else if ("bank_transfer".equals(lowerMethod) || "transfer".equals(lowerMethod)) {
            status = "PENDING";
        } else if ("wallet".equals(lowerMethod) || "mobile".equals(lowerMethod)) {
            status = "APPROVED";
        } else {
            status = "REJECTED";
        }

        if (request.getDescription() != null && request.getDescription().toLowerCase().contains("fraud")) {
            status = "REJECTED";
        }

        return new PaymentResponse(transactionId, status, "Processed " + request.getPaymentMethod());
    }
}

